const rawProfiles = $('Read Raw Profiles').all();
let classified = [];
try {
  classified = $('Read Already Classified').all();
} catch (e) {
  classified = [];
}

const classifiedUsernames = new Set(
  classified
    .filter(item => item.json && item.json.username)
    .map(item => item.json.username.toLowerCase())
);

const seen = new Set();
const unclassified = [];

for (const profile of rawProfiles) {
  const username = (profile.json.username || '').trim().toLowerCase();
  if (!username) continue;
  if (seen.has(username)) continue;
  if (classifiedUsernames.has(username)) continue;
  seen.add(username);
  unclassified.push(profile);
}

return unclassified.slice(0, 100);

// Prepare image URLs for Gemini vision analysis
// Select up to 8 images to analyze (Gemini can handle multiple)
const profile = $json;
const imageUrlsRaw = (profile.image_urls || '').split(',').map(u => u.trim()).filter(u => u && u.startsWith('http'));
const videoUrlsRaw = (profile.video_urls || '').split(',').map(u => u.trim()).filter(u => u && u.startsWith('http'));

// Take up to 8 images and 2 video thumbnails for analysis
const imagesToAnalyze = imageUrlsRaw.slice(0, 8);
// For videos, we can still send URLs - Gemini can handle video URLs
const videosToAnalyze = videoUrlsRaw.slice(0, 2);

return [{
  json: {
    ...profile,
    _images_to_analyze: imagesToAnalyze,
    _videos_to_analyze: videosToAnalyze,
    _has_media: imagesToAnalyze.length > 0 || videosToAnalyze.length > 0
  }
}];

// Build combined Gemini request - vision + classification in one call
const profile = $json;
const images = profile._images_to_analyze || [];
const videos = profile._videos_to_analyze || [];

const parts = [];

// Download images as base64 first
let downloadedCount = 0;
const maxImages = 8;

for (const imgUrl of images.slice(0, maxImages)) {
  try {
    const buffer = await this.helpers.httpRequest({
      method: 'GET',
      url: imgUrl,
      encoding: 'arraybuffer',
      returnFullResponse: false
    });
    const base64 = Buffer.from(buffer).toString('base64');
    parts.push({
      inlineData: {
        mimeType: 'image/jpeg',
        data: base64
      }
    });
    downloadedCount++;
  } catch (e) {
    // Skip failed downloads
  }
}

// Combined prompt: analyze images + profile data + classify
parts.push({
  text: `You are an expert luxury watch analyst classifying Instagram profiles for a luxury watch sourcing business. The business owner wants to find wealthy watch collectors who own rare/valuable watches that can be sourced or purchased.

== IMAGES ==
Above are ${downloadedCount} recent Instagram post images from @${profile.username}. Analyze them for watches, luxury items, and lifestyle indicators.

== PROFILE DATA ==
Username: ${profile.username || ''}
Full Name: ${profile.full_name || ''}
Bio: ${profile.bio || ''}
Followers: ${profile.follower_count || 0} | Following: ${profile.following_count || 0} | Posts: ${profile.post_count || 0}
Verified: ${profile.is_verified || false} | Business Account: ${profile.is_business || false}
Business Category: ${profile.business_category || ''}
Website: ${profile.external_url || ''}
Email Found: ${profile.email_in_bio || ''} | Phone Found: ${profile.phone_in_bio || ''}
Engagement Rate: ${profile.engagement_rate || ''}
Avg Likes: ${profile.avg_likes || 0} | Avg Comments: ${profile.avg_comments || 0}

== RECENT POST CAPTIONS ==
${(profile.recent_captions || 'N/A').substring(0, 3000)}

== HASHTAGS USED ==
${profile.hashtags || 'N/A'}

== MENTIONS ==
${profile.mentions || 'N/A'}

== POST LOCATIONS ==
${profile.recent_post_locations || 'N/A'}

== TASK ==
Combine your analysis of the images with the profile text data to produce an accurate classification.

Return ONLY valid JSON:
{
  "classification": "collector" | "dealer" | "replica_dealer" | "enthusiast" | "irrelevant",
  "confidence": "high" | "medium" | "low",
  "watch_brands": ["list of brands detected from images AND text"],
  "specific_watches": [
    {
      "brand": "brand",
      "model": "model",
      "reference": "ref if known",
      "estimated_value_usd": "range",
      "source": "image" | "text" | "both"
    }
  ],
  "total_collection_value_estimate": "estimated total value range",
  "net_worth_tier": "ultra-high" | "high" | "medium" | "unknown",
  "wealth_signals": ["specific indicators: cars, locations, lifestyle items spotted in images or text"],
  "ownership_type": "personal_collector" | "dealer_business" | "flipper" | "influencer" | "enthusiast_no_ownership" | "unclear",
  "sourcing_potential": "high" | "medium" | "low" | "none",
  "sourcing_reasoning": "why this person might or might not sell/source watches",
  "approach_suggestion": "how the business should approach this person",
  "priority_score": 1-10,
  "image_summary": "brief 1-2 sentence summary of what the images show",
  "reasoning": "2-3 sentence explanation of classification"
}

CRITICAL RULES - READ CAREFULLY:
1. ONLY report wealth signals you can DIRECTLY observe in images or text. NEVER fabricate or assume wealth signals like "private jet", "Ferrari", "designer clothing" unless you can clearly see them. If unsure, do NOT include them. An empty wealth_signals array is BETTER than a fabricated one.
2. Distinguish between OWNERSHIP and CONTENT SHARING. This is the MOST IMPORTANT distinction. Reposting watch photos, stock images, brand marketing, or memes is NOT ownership. ONLY count as ownership: personal wrist shots showing the SAME wrist/setting across posts, unboxing videos, explicit "my new" or "just picked up" language with matching images. If you cannot confirm ownership, classify as ENTHUSIAST.
3. Be SKEPTICAL of accounts with low followers (<1000) claiming high net worth collections. Small accounts rarely own $100K+ in watches.
4. Check for REPLICA/FAKE indicators: bio mentions "factory", "China factory", "AAA quality", "1:1", "clone", "copy", "rep", wholesale from China, suspiciously low prices for luxury watches, WhatsApp ordering. If detected, classify as "replica_dealer" and set priority_score to 0.
5. If someone\'s primary profession is NOT watches (e.g., realtor, fitness influencer, athlete, musician) and they post watch content, they are an ENTHUSIAST unless you see CLEAR evidence of 3+ personally owned luxury pieces worth $20K+ each.
6. Do NOT give priority_score above 6 unless you have STRONG, VERIFIED evidence of actual ownership of identifiable luxury watches worth $50K+. Most accounts should score 1-4.
7. net_worth_tier should be "unknown" unless there are 3+ clear, verified wealth indicators visible in images. Do not default to "ultra-high" or "high".
8. DEFAULT TO SKEPTICISM. When in doubt between collector and enthusiast, choose ENTHUSIAST. When in doubt between enthusiast and irrelevant, choose IRRELEVANT. It is much worse to over-classify than to under-classify.
9. Watch PAGES (accounts that aggregate/repost watch content from others) are NOT collectors. They are enthusiast pages at best. Look for original content vs reposts.
10. Accounts that primarily sell watch straps, accessories, or non-watch luxury goods are NOT collectors.

Classification guide:
- COLLECTOR: Owns watches personally with VERIFIED evidence (personal wrist shots showing the SAME wrist in multiple posts, explicit ownership statements with matching photos, collection displays in consistent settings). Must have CLEAR proof of ownership, not just proximity to watches. HIGH sourcing potential only if they have rare pieces they demonstrably own.
- DEALER: Business account with inventory posts showing multiple watches FOR SALE, pricing language, trade references, established watch dealer. Must show actual business operations, not just a bio claim.
- REPLICA_DEALER: Sells fake/replica watches. Bio mentions factory, China manufacturing, clone, 1:1 quality, or images show obvious fakes. Priority score MUST be 0.
- ENTHUSIAST: Appreciates watches, follows the scene, shares content, but LIMITED or NO ownership signals. This is the DEFAULT classification for anyone who posts watch content without clear ownership proof. Includes: watch pages, content aggregators, people whose main profession is unrelated, casual watch fans.
- IRRELEVANT: No meaningful watch content, bots, unrelated accounts, generic lifestyle accounts with occasional watch mention.

Priority scoring (BE VERY CONSERVATIVE - most accounts should score 1-4):
10 = Verified collector with CONFIRMED ownership of 5+ rare pieces ($200K+ total collection) AND multiple strong wealth signals clearly visible in images. This score should be EXTREMELY rare.
8-9 = Clear collector with 3+ luxury watches they demonstrably OWN shown on their wrist, consistent wealth signals across multiple posts
6-7 = Probable collector with clear ownership evidence of at least 2 luxury watches, or verified established dealer with genuine luxury inventory
4-5 = Some ownership evidence but uncertain, or dealer with limited inventory shown
2-3 = Enthusiast, content sharers, watch fans without ownership proof
1 = Barely relevant, generic accounts
0 = Replica dealers, fakes, spam, completely irrelevant`
});

const geminiBody = {
  contents: [{ parts: parts }],
  generationConfig: {
    temperature: 0.1,
    maxOutputTokens: 8192
  }
};

return [{
  json: {
    ...profile,
    _gemini_body: JSON.stringify(geminiBody),
    _image_count: downloadedCount,
    _video_count: videos.length
  }
}];

// Parse Gemini combined classification response
const geminiResponse = $json;
const profileData = $('Build Gemini Request').first()?.json || $('No Media Fallback').first()?.json || $('Prepare Media for Vision').item.json;

let classification = {};

try {
  const textContent = geminiResponse.candidates[0].content.parts.find(p => p.text)?.text || '';
  const jsonMatch = textContent.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    classification = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  classification = {
    classification: 'error',
    confidence: 'low',
    watch_brands: [],
    specific_watches: [],
    total_collection_value_estimate: 'unknown',
    net_worth_tier: 'unknown',
    wealth_signals: [],
    ownership_type: 'unclear',
    sourcing_potential: 'none',
    sourcing_reasoning: '',
    approach_suggestion: '',
    priority_score: 0,
    image_summary: 'Analysis failed',
    reasoning: `Failed to parse Gemini response: ${e.message}`
  };
}

// Format specific watches for sheet
const watchList = Array.isArray(classification.specific_watches)
  ? classification.specific_watches.map(w => {
      const parts = [w.brand, w.model, w.reference].filter(Boolean);
      const val = w.estimated_value_usd ? ` (~${w.estimated_value_usd})` : '';
      return parts.join(' ') + val;
    }).join(' | ')
  : (classification.specific_watches || '');

return [{
  json: {
    username: profileData.username,
    platform: profileData.platform || 'instagram',
    full_name: profileData.full_name,
    bio: profileData.bio,
    follower_count: profileData.follower_count,
    following_count: profileData.following_count,
    post_count: profileData.post_count,
    is_verified: profileData.is_verified,
    is_business: profileData.is_business,
    business_category: profileData.business_category,
    external_url: profileData.external_url,
    email_in_bio: profileData.email_in_bio,
    phone_in_bio: profileData.phone_in_bio,
    engagement_rate: profileData.engagement_rate,
    profile_url: profileData.profile_url || `https://instagram.com/${profileData.username}`,
    seed_account: profileData.seed_account,
    seed_type: profileData.seed_type,
    classification: classification.classification || 'unknown',
    confidence: classification.confidence || 'low',
    watch_brands: Array.isArray(classification.watch_brands) ? classification.watch_brands.join(', ') : (classification.watch_brands || ''),
    specific_watches: watchList,
    total_collection_value: classification.total_collection_value_estimate || 'unknown',
    net_worth_tier: classification.net_worth_tier || 'unknown',
    wealth_signals: Array.isArray(classification.wealth_signals) ? classification.wealth_signals.join(', ') : (classification.wealth_signals || ''),
    ownership_type: classification.ownership_type || 'unclear',
    sourcing_potential: classification.sourcing_potential || 'none',
    sourcing_reasoning: classification.sourcing_reasoning || '',
    approach_suggestion: classification.approach_suggestion || '',
    priority_score: classification.priority_score || 0,
    ai_reasoning: classification.reasoning || '',
    vision_summary: classification.image_summary || 'No vision analysis',
    images_analyzed: profileData._image_count || 0,
    classified_date: new Date().toISOString().split('T')[0]
  }
}];
